// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const data = $input.first().json.body.map(d => ({url: "https://www.pixiv.net/ajax/novel/"+d.id}))
const start_from = Number($('On form submission').first().json.start_from)
const end_to = Number($('On form submission').first().json.end_to)
const slice_from_index = (start_from === 0 ? 1 : start_from) - 1
const slice_end_index = (end_to === 0 ? data.length : end_to)

return data.slice(slice_from_index, slice_end_index)

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const start_from = Number($('On form submission').first().json.start_from)
const slice_index = (start_from === 0 ? 1 : start_from) - 1
const novel_count = $input.first().json.data[1].general_all_no
const ncode = $input.first().json.data[1].ncode.toLowerCase()
const urls = (new Array(novel_count)).fill(null).map((_, i) => `https://ncode.syosetu.com/${ncode}/${i + 1}/`)
return urls.map(d=> ({url: d})).slice(slice_index)

