function getNovelTags(ncode) {
  // 本好きの下剋上 小書痴的下剋上系列
  const likeBookSeries = ["n4830bu", "n4750dy", "n7835cj"];
  const likeBookSeriesRegex = new RegExp(likeBookSeries.join("|"));

  if (likeBookSeriesRegex.test(ncode)) {
    return ["本好きの下剋上"];
  }

  // サイレント・ウィッチ 沉默魔女的秘密系列
  const silentWitchSeries = ["n8356ga", "n5194gp", "n8978fv", "n7961jr"];
  const silentWitchSeriesRegex = new RegExp(silentWitchSeries.join("|"));
  if (silentWitchSeriesRegex.test(ncode)) {
    return ["サイレント・ウィッチ"];
  }
  // 痛いのは嫌なので防御力に極振りしたいと思います 怕痛的我，把防禦力點滿就對了
  const scaredToHurtSeries = ["n0358dh"];
  const scaredToHurtSeriesRegex = new RegExp(scaredToHurtSeries.join("|"));
  if (scaredToHurtSeriesRegex.test(ncode)) {
    return ["痛いのは嫌なので防御力に極振りしたいと思います"];
  }
  return undefined;
}

const windowsFileEscapeRegex = /[<>:"/\\|?*]/g;

const { title, series_title, author, content } = $input.first().json;
const [, , , ncode, episode] = $("Loop Over Items").first().json.url.split("/");
const series_title_and_author = (series_title + " " + author).replaceAll(
  windowsFileEscapeRegex,
  " ",
);
const indexPrefix = ncode + " " + episode;
const file_name = `${indexPrefix}-${title}_translated.txt`;
const folder_name = series_title_and_author;
const tags = getNovelTags(ncode);
const url = $("Loop Over Items").first().json.url;

return {
  title,
  indexPrefix,
  content,
  series_title_and_author,
  folder_name,
  series_title,
  file_name,
  url,
  tags: tags,
  author,
};

const set_cookie_arr = $input.first().json.headers["set-cookie"];
const cookie_str = $("Merge").first().json.Cookie;
if (set_cookie_arr) {
  const cookie_obj = {};
  cookie_str.split(";").forEach((item) => {
    item = item.trim();
    const [key, value] = item.split("=");
    cookie_obj[key] = value;
  });
  set_cookie_arr.forEach((item) => {
    item = item.split(";")[0];
    const [key, value] = item.split("=");
    cookie_obj[key] = value;
  });
  return {
    new_cookie_str: Object.entries(cookie_obj)
      .map(
        ([key, value]) =>
          `${encodeURIComponent(key)}=${encodeURIComponent(value)}`,
      )
      .join("; "),
  };
}
return {new_cookie_str: cookie_str}

const windowsFileEscapeRegex = /[<>:"/\\|?*]/g;

const this_novel_data = $input.first().json.body
const paragraphs = this_novel_data.body.content

const content = paragraphs.replaceAll("\n\n", "\n")

const tags = this_novel_data.body?.tags?.tags?.map(({ tag }) => tag);
const title = this_novel_data.body.title;
const series_title = this_novel_data.body?.seriesNavData?.title ?? title;
const author = this_novel_data.body?.userName
  .replaceAll(windowsFileEscapeRegex, " ")
  .trimEnd();
const indexPrefix =
  series_title + " " + (this_novel_data.body?.seriesNavData?.order ?? "");
const series_title_and_author = (series_title + " " + author).replaceAll(
    windowsFileEscapeRegex,
    " ",
  )
const folder_name = series_title_and_author
const file_name = `${indexPrefix}-${title}_translated.txt`
const url = $('Loop Over Items').item.json.url
return {
  title: title.replaceAll(windowsFileEscapeRegex, " "),
  indexPrefix: indexPrefix.replaceAll(windowsFileEscapeRegex, " "),
  content,
  series_title_and_author,
  folder_name,
  series_title,
  file_name,
  url: url.replaceAll('https://www.pixiv.net/ajax/novel/','https://www.pixiv.net/novel/show.php?id='),
  author,
  tags: tags,
};

